def fibonacci(n):
    if n < 0:
        raise ValueError("n must be non-negative")
    if n <= 1:
        return n

    def fib_pair(n):
        if n == 0:
            return (0, 1)
        a, b = fib_pair(n >> 1)
        c = a * (2 * b - a)
        d = a * a + b * b
        if n & 1:
            return (d, c + d)
        else:
            return (c, d)

    return fib_pair(n)[0]

def fibonacci(n):
    if n < 0:
        raise ValueError("n must be non-negative")
    if n <= 1:
        return n

    a, b = 0, 1
    bits = []
    k = n
    while k:
        bits.append(k & 1)
        k >>= 1
    bits.pop()

    for bit in reversed(bits):
        c = a * (2 * b - a)
        d = a * a + b * b
        if bit:
            a, b = d, c + d
        else:
            a, b = c, d

    return a

